import osimport timeimport socketfrom Searcher import search, devices# Планы:# Сделать удобный менеджер для выбора файлов, в идеале, чтобы сделать в контекстном менеджере# Windows вкладку для отправки через наш скрипт# Что такое cheksum:# https://www.geeksforgeeks.org/computer-networks/error-detection-code-checksum/# https://www.geeksforgeeks.org/computer-networks/error-detection-in-computer-networks/# https://elc.github.io/python-security/chapters/04_Checksum.html# https://www.geeksforgeeks.org/python/implementing-checksum-using-python/def read_file(target_file, chunk_size=8192):    with open('received_files/'+target_file, 'rb') as f:        while True:            bytes_read = f.read(chunk_size)            if not bytes_read:                break            yield bytes_readdef choose_file():    print('received_files:')    files = os.listdir('received_files')    for num,file in enumerate(os.listdir('received_files')):        print('-',num,'-',file)    target_file = files[int(input('Введите номер файла для отправки: '))]    print(f'Выбран файл: {target_file}')    file_info = {'name': target_file, 'size': os.path.getsize('received_files/'+target_file), 'checksum': "Тут ебля"}    # size = os.path.getsize('received_files/'+target_file)    # print(size/2)    devices = search()    print(devices)    # server = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)    # server.setsockopt(socket.SOL_SOCKET, socket.SO_BROADCAST, True)    # for i in read_file(target_file):    #     server.sendall(i.encode("utf-8"))    #     print(f"Отправлено широковещательное сообщение: {i}")choose_file()